/* eslint-disable no-console */
/**
 * useRoomAIMessages
 *
 * 封装 room-ai 所有消息的生命周期管理：
 * - 本地 IDB 的读写删
 * - 服务端同步（insert / upsert / delete / syncOnMount）
 * - 分页加载
 * - EventEmitter 事件监听（AddRoomAIMessage）
 *
 * room-ai.tsx 通过此 hook 获取操作函数，专注于视图渲染。
 */

import type { Dispatch, SetStateAction } from 'react';
import { useCallback, useEffect, useState } from 'react';

import type { SyncChatMessage } from '../messages/types';

import eventEmitter, { Actions } from '../lib/EventEmitter';
import { createChatAssistantIntroduceMessage } from '../lib/message-creater';
import { sendSCMDelete, sendSCMInsert, sendSCMUpsert } from '../agent/mcp-tools/handlers/wsSyncChatMessageHandler';
import RoomStorage from '../room-storage';
import { ChataiStores } from '../store';

// ===========================
// 类型
// ===========================

export interface PageInfo {
  lastTime: number | undefined;
  hasMore: boolean;
}

interface Options {
  chatId: string | undefined;
  setMessages: Dispatch<SetStateAction<SyncChatMessage[]>>;
  scrollToBottom: (behavior?: ScrollBehavior) => void;
  scrollLocked: () => void;
}

interface Result {
  pageInfo: PageInfo;
  /** 写入 IDB 并触发 syncInsert，不改变 UI（适用于 handleInputSubmit 中 append 之后） */
  persistInsert: (message: SyncChatMessage) => void;
  /** 写入 IDB 并触发 syncUpsert，不改变 UI（适用于 onFinish 回调） */
  persistUpsert: (message: SyncChatMessage) => void;
  /** 追加到 UI + 写入 IDB + syncInsert（适用于非流式直接插入的消息） */
  insertMessage: (message: SyncChatMessage) => void;
  /** 从 UI 移除 + 从 IDB 删除 + syncDelete */
  deleteMessage: (messageId: string) => void;
  /** 加载更多（向上翻页） */
  handleLoadMore: () => Promise<void>;
}

// ===========================
// Hook
// ===========================

export function useRoomAIMessages({
  chatId,
  setMessages,
  scrollToBottom,
  scrollLocked,
}: Options): Result {
  const [pageInfo, setPageInfo] = useState<PageInfo>({
    lastTime: undefined,
    hasMore: true,
  });

  // ── 私有：写入本地 IDB（不触发 sync） ──────────────────────────────
  const storeMessagesToDB = useCallback((messagesToStore: SyncChatMessage | SyncChatMessage[]) => {
    if (!chatId) return;
    const arr = Array.isArray(messagesToStore) ? messagesToStore : [messagesToStore];
    // 确保每条消息都带有 chatId，否则 chatId_timestamp 复合索引无法命中
    arr.forEach((msg) => ChataiStores.message?.storeMessage({ ...msg, chatId }));
  }, [chatId]);

  // ── chatId 变更：初始化 + 加载本地消息 + 服务端增量同步 ─────────────
  useEffect(() => {
    if (!chatId) return;

    let cancelled = false;

    setMessages([]);
    // 加载完成前禁用 loadMore，防止空列表 sentinel 可见时触发重复加载
    setPageInfo({ lastTime: undefined, hasMore: false });

    const load = async () => {
      // 加载本地消息
      const res = await ChataiStores.message?.getMessages(chatId, undefined, 10);
      if (cancelled) return;
      if (res?.messages) {
        setMessages(res.messages);
        setPageInfo({ lastTime: res.lastTime, hasMore: res.hasMore });
      }
      // 本地和服务端均无消息，插入介绍消息
      const hasLocalMessages = (res?.messages?.length ?? 0) > 0;
      if (!hasLocalMessages) {
        const introMessage = createChatAssistantIntroduceMessage(chatId);
        storeMessagesToDB(introMessage);
        setMessages([introMessage]);
      }

      requestAnimationFrame(() => scrollToBottom('instant'));
    };

    load().catch((err) => console.warn('[useRoomAIMessages] load failed:', err));
    RoomStorage.updateRoomAIData(chatId, 'unreadCount', 0);

    return () => {
      cancelled = true;
    };
  }, [chatId, setMessages, scrollToBottom, storeMessagesToDB]);

  // ── 公开：仅持久化（不改 UI），用于流式消息 ──────────────────────────
  const persistInsert = useCallback((message: SyncChatMessage) => {
    storeMessagesToDB(message);
    sendSCMInsert(message);
  }, [storeMessagesToDB]);

  const persistUpsert = useCallback((message: SyncChatMessage) => {
    storeMessagesToDB(message);
    sendSCMUpsert(message);
  }, [storeMessagesToDB]);

  // ── 公开：追加到 UI + 持久化，用于非流式消息 ─────────────────────────
  const insertMessage = useCallback((message: SyncChatMessage) => {
    setMessages((prev) => [...prev, message]);
    storeMessagesToDB(message);
    sendSCMInsert(message);
  }, [setMessages, storeMessagesToDB]);

  // ── 公开：删除（UI + IDB + 服务端） ────────────────────────────────
  const deleteMessage = useCallback((messageId: string) => {
    ChataiStores.message?.delMessage(messageId).then(() => {
      setMessages((prev) => prev.filter((m) => m.id !== messageId));
      sendSCMDelete({ localId: messageId });
    });
  }, [setMessages]);

  // ── 公开：加载更多（向上翻页） ──────────────────────────────────────
  const handleLoadMore = useCallback(() => {
    scrollLocked();
    return new Promise<void>((resolve) => {
      if (!chatId) {
        resolve();
        return;
      }
      ChataiStores.message?.getMessages(chatId, pageInfo.lastTime, 10)?.then((res) => {
        if (res.messages) {
          setMessages((prev) => [...res.messages, ...prev]);
        }
        setPageInfo({ lastTime: res.lastTime, hasMore: res.hasMore });
        resolve();
      });
    });
  }, [chatId, pageInfo.lastTime, scrollLocked, setMessages]);

  // ── EventEmitter：外部事件触发的消息（约定提醒、摘要等） ───────────────
  const handleAddSummaryMessage = useCallback((message: SyncChatMessage) => {
    storeMessagesToDB(message);
    sendSCMInsert(message);
    setMessages((prev) => {
      const idx = prev.findIndex((m) => m.id === message.id);
      if (idx !== -1) {
        const next = [...prev];
        next[idx] = message;
        return next;
      }
      return [...prev, message];
    });
  }, [setMessages, storeMessagesToDB]);

  useEffect(() => {
    eventEmitter.on(Actions.AddRoomAIMessage, handleAddSummaryMessage);
    return () => {
      eventEmitter.off(Actions.AddRoomAIMessage, handleAddSummaryMessage);
    };
  }, [handleAddSummaryMessage]);

  return {
    pageInfo,
    persistInsert,
    persistUpsert,
    insertMessage,
    deleteMessage,
    handleLoadMore,
  };
}
