/* eslint-disable no-null/no-null */
import React, {
  memo,
  useCallback, useEffect, useRef, useState,
} from 'react';
import { getActions } from '../../../global';

import type { SyncChatMessage } from '../messages/types';

import eventEmitter, { Actions } from '../lib/EventEmitter';
import { createAssistantMessage, createGoogleLoginMessage, createGoogleMeetingMessage, createGoogleMeetingSuccessMessage, createUpgradeTipMessage, createUserMessage } from '../lib/message-creater';
import { CHATAI_IDB_STORE } from '../../../util/browser/idb';
import buildClassName from '../../../util/buildClassName';
import { useRoomAIMessages } from '../hook/use-room-ai-messages';
import { useScrollToBottom } from '../hook/use-scroll-to-bottom';
import { Messages } from '../messages';
import { ChataiStores } from '../store';
import { useRoomAIStore } from '../store/zustand/room-ai-store';
import RoomActions from './room-actions';
import { RoomAIInput } from './room-ai-input';

import { useAgentChat } from '../agent/hooks/useAgentChat';

import SelectedMessagesBanner from './SelectedMessagesBanner';

import './room-ai.scss';
import styles from './room-ai.module.scss';

const RoomAIInner = () => {
  const { showNotification, clearChatAISelectedMessages } = getActions();
  const chatId = useRoomAIStore((s) => s.chatId);
  const selectedMessages = useRoomAIStore((s) => s.selectedMessages);
  const [isLoading, setIsLoading] = useState(false);
  const tokenRef = useRef<string | null>(null);
  const {
    scrollToBottom, scrollLocked, isScrollLock,
  } = useScrollToBottom();

  const {
    messages,
    setMessages,
    append,
    stop,
    status,
    currentPhase,
    toolCalls,
  } = useAgentChat({
    chatId,
    selectedMessages,
    showThinking: false,
    showToolCalls: true,
    detailedCitations: true,
    onError: (error) => {
      try {
        const data = JSON.parse(error.message);
        if (data.code === 102 || data.code === 103) {
          if (chatId) {
            const upgradeTip = createUpgradeTipMessage({ chatId });
            insertMessage(upgradeTip);
          }
        }
      } catch (e) {
        showNotification({
          message: error.message || 'An error occurred',
        });
      }
    },
    onFinish: (result) => {
      // eslint-disable-next-line no-console
      console.log('[RoomAI] Finished:', result);
      setMessages((prev) => {
        const lastMessage = prev[prev.length - 1];
        if (lastMessage) {
          persistUpsert(lastMessage);
        }
        return prev;
      });
    },
  });

  const {
    pageInfo,
    persistInsert,
    persistUpsert,
    insertMessage,
    deleteMessage,
    handleLoadMore,
  } = useRoomAIMessages({
    chatId,
    setMessages,
    scrollToBottom,
    scrollLocked,
  });

  useEffect(() => {
    if (!isScrollLock) {
      scrollToBottom();
    }
  }, [isScrollLock, messages, scrollToBottom]);

  useEffect(() => {
    CHATAI_IDB_STORE.get('google-token').then((token: any) => {
      if (token) {
        tokenRef.current = token;
      }
    });
  }, []);

  const handleCreateCalendarSuccess = useCallback((payload: any) => {
    const { message, response } = payload;
    if (response?.error) {
      showNotification({
        message: response.error?.message || 'Create Calendar Failed',
      });
      if (response.error?.code === 401 || response.error?.code === 403) {
        deleteMessage(message?.id);
        if (chatId) {
          insertMessage(createGoogleLoginMessage({ chatId }));
        }
      }
    } else {
      deleteMessage(message?.id);
      if (chatId) {
        const appendMessages: SyncChatMessage[] = [
          createAssistantMessage({ message: 'I\'ll send the meeting invitation shortly. Please check your inbox in the next few minutes.', chatId }),
          createGoogleMeetingSuccessMessage({ metadata: response as Record<string, any>, chatId }),
        ];
        appendMessages.forEach((msg) => insertMessage(msg));
      }
    }
  }, [chatId, deleteMessage, insertMessage]);

  const updateToken = useCallback((payload: { message: SyncChatMessage; token: string }) => {
    const { message, token } = payload;
    tokenRef.current = token;
    if (message) {
      ChataiStores.message?.delMessage(message.id);
      setMessages((prev) => prev.filter((item) => item.id !== message.id));
    }
  }, [setMessages]);

  const handleGoogleAuthSuccess = useCallback(() => {
    if (chatId) {
      insertMessage(createGoogleMeetingMessage({ chatId }));
    }
  }, [insertMessage, chatId]);

  const handleInputSubmit = useCallback((value: string) => {
    scrollToBottom();
    if (!chatId) return;
    const newMessage = createUserMessage({ message: value, chatId });
    append(newMessage);
    persistInsert(newMessage);
    clearChatAISelectedMessages({});
  }, [append, clearChatAISelectedMessages, persistInsert, scrollToBottom, chatId]);

  useEffect(() => {
    eventEmitter.on(Actions.CreateCalendarSuccess, handleCreateCalendarSuccess);
    eventEmitter.on(Actions.UpdateGoogleToken, updateToken);
    eventEmitter.on(Actions.GoogleAuthSuccess, handleGoogleAuthSuccess);
    eventEmitter.on(Actions.AskRoomAI, handleInputSubmit);
    return () => {
      eventEmitter.off(Actions.CreateCalendarSuccess, handleCreateCalendarSuccess);
      eventEmitter.off(Actions.UpdateGoogleToken, updateToken);
      eventEmitter.off(Actions.GoogleAuthSuccess, handleGoogleAuthSuccess);
      eventEmitter.off(Actions.AskRoomAI, handleInputSubmit);
    };
  }, [handleCreateCalendarSuccess, handleGoogleAuthSuccess, handleInputSubmit, updateToken]);

  return (
    <div className={buildClassName(styles.rightPanelBg, 'right-panel-chat-ai')}>
      <Messages
        className="chat-ai-output-wrapper flex-1"
        isLoading={isLoading}
        status={status}
        messages={messages}
        currentPhase={currentPhase}
        toolCalls={toolCalls}
        deleteMessage={deleteMessage}
        loadMore={handleLoadMore}
        hasMore={pageInfo.hasMore}
        chatId={chatId!}
      />

      <div className="px-[16px] pb-4">
        <RoomActions setIsLoading={(s) => setIsLoading(s)} insertMessage={insertMessage} chatId={chatId} />
        <div className="flex flex-col gap-2 w-full rounded-[20px] border border-[#E5E5E5] bg-white dark:bg-black px-[14px] py-[10px]">
          <div>
            {selectedMessages && selectedMessages.length > 0 && (
              <SelectedMessagesBanner selectedMessages={selectedMessages} />
            )}
            <RoomAIInput
              status={status}
              stop={stop}
              setMessages={setMessages}
              handleInputSubmit={handleInputSubmit}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

const RoomAI = memo(RoomAIInner);

export default RoomAI;
