/* eslint-disable no-null/no-null */
/**
 * useGlobalSummaryMessages
 *
 * 封装 global-summary 所有消息的生命周期管理：
 * - 本地 IDB 的读写删
 * - 分页加载
 * - EventEmitter 事件监听（AddSummaryMessage、AddUrgentMessage、ChatAIStoreReady）
 *
 * global-summary.tsx 通过此 hook 获取操作函数，专注于视图渲染。
 */

import type { Dispatch, SetStateAction } from 'react';
import { useCallback, useEffect, useState } from 'react';

import type { SyncChatMessage } from '../messages/types';

import { Actions } from '../lib/EventEmitter';
import { createGlobalIntroduceMessage } from '../lib/message-creater';
import { ChataiStores } from '../store';
import { GLOBAL_SUMMARY_CHATID } from '../variables';
import { useEventListener } from './useEventBus';

// ===========================
// 类型
// ===========================

export interface GlobalSummaryPageInfo {
  lastTime: number | undefined;
  hasMore: boolean;
}

interface Options {
  setMessages: Dispatch<SetStateAction<SyncChatMessage[]>>;
  scrollToBottom: (behavior?: ScrollBehavior) => void;
  scrollLocked: () => void;
}

interface Result {
  summaryMessages: SyncChatMessage[];
  setSummaryMessages: Dispatch<SetStateAction<SyncChatMessage[]>>;
  pageInfo: GlobalSummaryPageInfo;
  storeMessagesToDB: (messagesToStore: SyncChatMessage | SyncChatMessage[]) => void;
  handleLoadMore: () => Promise<void>;
  deleteMessage: (messageId: string) => void;
}

// ===========================
// Hook
// ===========================

export function useGlobalSummaryMessages({
  setMessages,
  scrollToBottom,
  scrollLocked,
}: Options): Result {
  const [summaryMessages, setSummaryMessages] = useState<SyncChatMessage[]>([]);
  const [pageInfo, setPageInfo] = useState<GlobalSummaryPageInfo>({
    lastTime: undefined,
    hasMore: true,
  });

  // ── 私有：写入本地 IDB ──────────────────────────────────────────────
  const storeMessagesToDB = useCallback((messagesToStore: SyncChatMessage | SyncChatMessage[]) => {
    const messagesArray = Array.isArray(messagesToStore) ? messagesToStore : [messagesToStore];
    messagesArray.forEach((msg) => {
      ChataiStores.summary?.storeMessage(msg);
    });
  }, []);

  // ── 公开：加载历史消息 ────────────────────────────────────────────
  const getSummaryHistory = useCallback(async () => {
    const res = await ChataiStores.summary?.getMessages(undefined, 30);
    if (res && res.messages) {
      setSummaryMessages(res.messages ?? []);
      setPageInfo({
        lastTime: res.lastTime,
        hasMore: res.hasMore,
      });
    }
    // 本地和服务端均无消息，插入介绍消息
    const hasLocalMessages = (res?.messages?.length ?? 0) > 0;
    if (!hasLocalMessages) {
      const introMessage = createGlobalIntroduceMessage({ chatId: GLOBAL_SUMMARY_CHATID });
      storeMessagesToDB(introMessage);
      setMessages([introMessage]);
    }

    requestAnimationFrame(() => {
      scrollToBottom('instant');
    });
  }, [scrollToBottom, setMessages, storeMessagesToDB]);

  // ── 公开：加载更多（向上翻页）────────────────────────────────────
  const handleLoadMore = useCallback(() => {
    scrollLocked();
    return new Promise<void>((resolve) => {
      ChataiStores.summary?.getMessages(pageInfo?.lastTime, 10)?.then((res) => {
        if (res.messages) {
          setSummaryMessages((prev) => [...(res.messages ?? []), ...prev]);
        }
        setPageInfo({
          lastTime: res.lastTime,
          hasMore: res.hasMore,
        });
        resolve();
      });
    });
  }, [pageInfo?.lastTime, scrollLocked]);

  // ── 公开：删除（UI + IDB）───────────────────────────────────────
  const deleteMessage = useCallback((messageId: string) => {
    scrollLocked();
    ChataiStores.summary?.delMessage(messageId).then(() => {
      setSummaryMessages((prev) => prev.filter((m) => m.id !== messageId));
      setMessages((prev) => prev.filter((m) => m.id !== messageId));
    });
  }, [scrollLocked, setMessages]);

  // ── EventEmitter：外部注入的摘要消息 ────────────────────────────
  const handleAddSummaryMessage = useCallback((message: SyncChatMessage) => {
    setSummaryMessages((prev) => [...prev, message]);
    storeMessagesToDB(message);
  }, [storeMessagesToDB]);

  useEventListener(Actions.AddSummaryMessage, handleAddSummaryMessage);
  useEventListener(Actions.ChatAIStoreReady, getSummaryHistory);

  useEffect(() => {
    getSummaryHistory();
  }, [getSummaryHistory]);

  return {
    summaryMessages,
    setSummaryMessages,
    pageInfo,
    storeMessagesToDB,
    handleLoadMore,
    deleteMessage,
  };
}
